import React, { useEffect, useState } from 'react'
import PropTypes from 'prop-types'
import { Button, Slider, Tooltip } from '/src/components'
import { Tab } from '@headlessui/react'
import { DistanceFieldScene } from '../components/distance-field/DistanceFieldScene'
import { MAPS, EnvironmentMaps } from '../components/distance-field/EnvironmentMaps'
import { Gallery } from '../components/distance-field/Gallery'

import glslSettingsTemplate from '/src/distance-field-page/glslSettingsTemplate'
import glslCollisionPass from '/src/distance-field-page/glslCollisionPass'
import glslSdfProgramTemplate from '/src/distance-field-page/glslSdfProgramTemplate'
import glslLightingPass from '/src/distance-field-page/glslLightingPass'

import glslMandelbulb from '/src/graphics/gl/sdfs/mandelbulb'
import glslMandelbulbLighting from '/src/graphics/gl/sdfs/mandelbulbLighting'
import glslMandelbox from '/src/graphics/gl/sdfs/mandelbox'
import glslMandelboxLighting from '/src/graphics/gl/sdfs/mandelboxLighting'

let AceEditor = () => <></>

const GALLERY = [
    {
        name: 'Mandelbulb',
        thumbnail: '',
        collisionShader: glslMandelbulb,
        lightingShader: glslMandelbulbLighting,
        envMapIndex: 0,
    },
    {
        name: 'Mandelbox',
        thumbnail: '',
        collisionShader: glslMandelbox,
        lightingShader: glslMandelboxLighting,
        envMapIndex: 1,
    },
]

const AdjustmentSlider = (props) => (
    <>
        <Slider.Root {...props}>
            <Slider.Track>
                <Slider.Range />
            </Slider.Track>
            <Slider.Thumb />
        </Slider.Root>
        <div className="flex flex-row items-center w-full space-x-2 text-sm font-bold">
            <div className="grow-0">{props.min}</div>
            <div className="grow" />
            <div className="grow-0 text-right">{props.max.toLocaleString()}</div>
        </div>
    </>
)
AdjustmentSlider.propTypes = {
    min: PropTypes.number,
    max: PropTypes.number,
}

const controlLabelClasses = 'text-sm font-bold mb-2 inline-block'

const AdjustmentsTab = ({ children }) => {
    const tabClass = ({ selected }) =>
        `rounded-lg text-sm font-medium focus:outline-none pr-6 font-bold ${
            selected
                ? 'text-black dark:text-white font-extrabold tracking-wide'
                : 'text-black/50 hover:text-black/75 dark:text-white/50 dark:hover:text-white/75'
        }`
    return <Tab className={tabClass}>{children}</Tab>
}

AdjustmentsTab.propTypes = {
    children: PropTypes.node,
}

const ShaderFileTab = ({ children }) => {
    const tabClass = ({ selected }) =>
        `text-sm text-slate-500 px-4 py-2 first:border-l border-neutral-100 ${
            selected ? 'bg-white text-slate-900' : ''
        }`.trim()
    return <Tab className={tabClass}>{children}</Tab>
}
ShaderFileTab.propTypes = {
    children: PropTypes.node,
}

const Panel = ({ children, className }) => {
    return <Tab.Panel className={`h-full ${className ?? ''}`.trim()}>{children}</Tab.Panel>
}

Panel.propTypes = {
    className: PropTypes.string,
    children: PropTypes.node,
}

const Page = () => {
    const [isPlaying, setPlaying] = useState(true)
    const [showAdjustments, setShowAdjustments] = useState(false)

    const [fov, setFov] = useState(70)
    const handleChangeFov = (values) => {
        setFov(values[0])
    }
    const [maxSteps, setMaxSteps] = useState(150)
    const handleChangeMaxSteps = (values) => {
        setMaxSteps(values[0])
    }

    const [distanceFieldOcclusionSamples, setDistanceFieldOcclusionSamples] = useState(5)
    const handleChangeDistanceFieldOcclusionSamples = (values) => {
        setDistanceFieldOcclusionSamples(values[0])
    }
    const [distanceFieldOcclusionDistance, setDistanceFieldOcclusionDistance] = useState(0.4)
    const handleChangeDistanceFieldOcclusionDistance = (values) => {
        setDistanceFieldOcclusionDistance(values[0])
    }

    const [programError, setProgramError] = useState([])
    const handleProgramError = (error) => {
        setProgramError(error)
    }

    const [envMap, setEnvMap] = useState(MAPS[0].map)

    const [time, setTime] = useState(0)
    useEffect(() => {
        requestAnimationFrame(() => {
            if (isPlaying) {
                setTime(time === 1e6 ? 0 : time + 1)
            }
        })
    }, [isPlaying, time])

    const [glslLive, setGlslLive] = useState(
        glslSdfProgramTemplate(GALLERY[0].collisionShader, GALLERY[0].lightingShader)
    )
    const handleChangeGlslLive = (newValue) => {
        setGlslLive(newValue)
        setProgramError([])
    }
    const handlePlayPause = () => {
        setPlaying(!isPlaying)
    }
    const handleShowAdjustments = () => {
        setShowAdjustments(true)
    }
    const handleCloseAdjustments = () => {
        setShowAdjustments(false)
    }
    const handleCloseAdjustmentsFromBack = (e) => {
        if (e.currentTarget === e.target) {
            handleCloseAdjustments()
        }
    }

    const [showGallery, setShowGallery] = useState(false)
    const handleCloseGallery = () => {
        setShowGallery(false)
    }
    const handleOpenGallery = () => {
        setShowGallery(true)
    }
    const handleSelectGalleryItem = ({ collisionShader, lightingShader, envMapIndex }) => {
        setShowGallery(false)
        setGlslLive(glslSdfProgramTemplate(collisionShader, lightingShader))
        setEnvMap(MAPS[envMapIndex].map ?? 0)
    }

    const glslSettings = glslSettingsTemplate({
        maxSteps,
        distanceFieldOcclusionSamples,
        distanceFieldOcclusionDistance,
    })

    useEffect(() => {
        //Fix window is not defined in deployment
        AceEditor = require('react-ace').default
        require('ace-builds/src-noconflict/mode-glsl')
        require('brace')
        require('brace/ext/searchbox')
    }, [])

    return (
        <>
            <main className="w-screen h-screen bg-black">
                <div
                    className={`fixed w-full h-full transition-transform ${
                        showAdjustments ? 'translate-x-1/4' : 'translate-x-0'
                    }`}
                >
                    <DistanceFieldScene
                        envMap={envMap}
                        fov={fov}
                        time={time / 1e6}
                        maxSteps={maxSteps}
                        glslSettings={glslSettings}
                        glslLive={glslLive}
                        onProgramError={handleProgramError}
                    />
                </div>
                <div className="flex fixed bottom-0 justify-center w-screen">
                    <div className="flex inline-block bg-white/60 dark:bg-black/60 backdrop-blur px-5 py-4 rounded-xl items-center mb-14">
                        <Button onClick={handlePlayPause}>
                            {isPlaying ? (
                                <svg
                                    xmlns="http://www.w3.org/2000/svg"
                                    className="h-5 w-5"
                                    viewBox="0 0 24 24"
                                    stroke="none"
                                    fill="currentColor"
                                >
                                    <path
                                        d="M6.56372 1.99999L6.56372 1.99999C7.66828 1.99999 8.56372 2.89542 8.56372 3.99999L8.56372 20C8.56372 21.1046 7.66828 22 6.56372 22L6.56372 22C5.45915 22 4.56372 21.1046 4.56372 20L4.56372 3.99999C4.56372 2.89542 5.45915 1.99999 6.56372 1.99999Z"
                                        opacity="1"
                                    />
                                    <path
                                        d="M17.4363 1.99999L17.4363 1.99999C18.5409 1.99999 19.4363 2.89542 19.4363 3.99999L19.4363 20C19.4363 21.1046 18.5409 22 17.4363 22L17.4363 22C16.3318 22 15.4363 21.1046 15.4363 20L15.4363 3.99999C15.4363 2.89542 16.3318 1.99999 17.4363 1.99999Z"
                                        opacity="1"
                                    />
                                </svg>
                            ) : (
                                <svg
                                    xmlns="http://www.w3.org/2000/svg"
                                    className="h-5 w-5"
                                    viewBox="0 0 24 24"
                                    stroke="currentColor"
                                    fill="currentColor"
                                >
                                    <path d="M20.6731 12.0443L3.32694 22L3.37815 2L20.6731 12.0443Z" />
                                </svg>
                            )}
                        </Button>
                        <div className="h-1/2 border border-black dark:border-white mx-3" />
                        <Tooltip delayDuration={200}>
                            <Tooltip.Trigger asChild>
                                <Button onClick={handleOpenGallery}>
                                    <svg
                                        xmlns="http://www.w3.org/2000/svg"
                                        className="h-6 w-6"
                                        viewBox="0 0 20 20"
                                        fill="currentColor"
                                    >
                                        <path
                                            fillRule="evenodd"
                                            d="M4 3a2 2 0 00-2 2v10a2 2 0 002 2h12a2 2 0 002-2V5a2 2 0 00-2-2H4zm12 12H4l4-8 3 6 2-4 3 6z"
                                            clipRule="evenodd"
                                        />
                                    </svg>
                                </Button>
                            </Tooltip.Trigger>
                            <Tooltip.Content side="top">Gallery</Tooltip.Content>
                        </Tooltip>
                        <Tooltip delayDuration={200}>
                            <Tooltip.Trigger asChild>
                                <Button onClick={handleShowAdjustments}>
                                    <svg
                                        xmlns="http://www.w3.org/2000/svg"
                                        className="h-6 w-6"
                                        fill="none"
                                        viewBox="0 0 24 24"
                                        stroke="currentColor"
                                    >
                                        <path
                                            strokeLinecap="round"
                                            strokeLinejoin="round"
                                            strokeWidth={2}
                                            d="M12 6V4m0 2a2 2 0 100 4m0-4a2 2 0 110 4m-6 8a2 2 0 100-4m0 4a2 2 0 110-4m0 4v2m0-6V4m6 6v10m6-2a2 2 0 100-4m0 4a2 2 0 110-4m0 4v2m0-6V4"
                                        />
                                    </svg>
                                </Button>
                            </Tooltip.Trigger>
                            <Tooltip.Content side="top">Adjustments</Tooltip.Content>
                        </Tooltip>
                        {/* 
                        <Tooltip delayDuration={200}>
                            <Tooltip.Trigger asChild>
                                <Button>?</Button>
                            </Tooltip.Trigger>
                            <Tooltip.Content side="top">About this experiment</Tooltip.Content>
                        </Tooltip>
                        */}
                    </div>
                </div>
                <div
                    className={`fixed h-full w-full ${showAdjustments ? 'pointer-events-auto' : 'pointer-events-none'}`}
                    onClick={handleCloseAdjustmentsFromBack}
                >
                    {/* For the ace-editor annotation tooltip to be in the right position, only left side works. */}
                    <div
                        className="transition-transform duration-250 w-3/5 h-full fixed py-4 pl-4"
                        style={{ transform: showAdjustments ? 'translateX(0%)' : 'translateX(-101%)' }}
                    >
                        <div className="flex flex-col h-full rounded-lg overflow-hidden bg-white/90 dark:bg-black/90 backdrop-blur">
                            <Tab.Group>
                                <div className="flex">
                                    <Tab.List className="flex space-x-1 p-6">
                                        <AdjustmentsTab>Graphics</AdjustmentsTab>
                                        <AdjustmentsTab>Shader editor</AdjustmentsTab>
                                    </Tab.List>
                                    <div className="grow" />
                                    <Button className="font-medium text-xl" onClick={handleCloseAdjustments}>
                                        &times;
                                    </Button>
                                </div>
                                <Tab.Panels className="h-full text-black dark:text-white">
                                    <Panel className="p-6 overflow-auto">
                                        Distance field Ambient Occlusion
                                        <div className="mt-3">
                                            <label className={controlLabelClasses}>
                                                Samples: {distanceFieldOcclusionSamples}
                                            </label>
                                            <div className="w-full">
                                                <AdjustmentSlider
                                                    defaultValue={[5]}
                                                    min={0}
                                                    max={20}
                                                    step={1}
                                                    onValueChange={handleChangeDistanceFieldOcclusionSamples}
                                                    value={[distanceFieldOcclusionSamples]}
                                                />
                                            </div>
                                        </div>
                                        <div className="mt-3">
                                            <label className={controlLabelClasses}>
                                                Max Distance: {distanceFieldOcclusionDistance}
                                            </label>
                                            <div className="w-full">
                                                <AdjustmentSlider
                                                    defaultValue={[15]}
                                                    min={0.02}
                                                    max={2}
                                                    step={0.01}
                                                    onValueChange={handleChangeDistanceFieldOcclusionDistance}
                                                    value={[distanceFieldOcclusionDistance]}
                                                />
                                            </div>
                                        </div>
                                        <div className="mt-12">Camera</div>
                                        <div className="mt-3">
                                            <label className={controlLabelClasses}>FOV: {fov}</label>
                                            <div className="w-full">
                                                <AdjustmentSlider
                                                    value={[fov]}
                                                    min={10}
                                                    max={120}
                                                    step={1}
                                                    onValueChange={handleChangeFov}
                                                />
                                            </div>
                                        </div>
                                        <div className="mt-12">Ray Marcher</div>
                                        <div className="mt-3">
                                            <label className={controlLabelClasses}>Max Steps: {maxSteps}</label>
                                            <div className="w-full">
                                                <AdjustmentSlider
                                                    value={[maxSteps]}
                                                    min={50}
                                                    max={1000}
                                                    step={1}
                                                    onValueChange={handleChangeMaxSteps}
                                                />
                                            </div>
                                        </div>
                                        <div className="mt-12">Baked Environment Map Materials</div>
                                        <div className="my-3">
                                            <EnvironmentMaps value={envMap} onSelect={setEnvMap} />
                                        </div>
                                    </Panel>
                                    <Panel className="flex flex-col">
                                        <Tab.Group>
                                            <div className="flex bg-neutral-100">
                                                <ShaderFileTab>
                                                    sdf.glsl{' '}
                                                    <span className="text-xs italic text-red-400">
                                                        (<span className="text-red-500 font-extrabold">&bull;</span>{' '}
                                                        Live)
                                                    </span>
                                                </ShaderFileTab>
                                                <ShaderFileTab>
                                                    settings.glsl{' '}
                                                    <span className="text-xs text-slate-400 italic">(Readonly)</span>
                                                </ShaderFileTab>
                                                <ShaderFileTab>
                                                    collision-pass.glsl{' '}
                                                    <span className="text-xs text-slate-400 italic">(Readonly)</span>
                                                </ShaderFileTab>
                                                <ShaderFileTab>
                                                    light-pass.glsl{' '}
                                                    <span className="text-xs text-slate-400 italic">(Readonly)</span>
                                                </ShaderFileTab>
                                            </div>
                                            <Tab.Panels className="grow">
                                                <Panel>
                                                    <AceEditor
                                                        className="shadow-none"
                                                        height="100%"
                                                        width="100%"
                                                        mode="glsl"
                                                        name="sdf-code-editor"
                                                        value={glslLive}
                                                        onChange={handleChangeGlslLive}
                                                        setOptions={{ printMargin: 120, scrollPastEnd: true }}
                                                        annotations={programError.map(({ code, text, ...error }) => ({
                                                            type: 'error',
                                                            text: `${code}: ${text}`,
                                                            ...error,
                                                        }))}
                                                    />
                                                </Panel>
                                                <Panel>
                                                    <AceEditor
                                                        className="shadow-none"
                                                        height="100%"
                                                        width="100%"
                                                        mode="glsl"
                                                        name="settings-shader-reference"
                                                        setOptions={{ printMargin: 120, readOnly: true }}
                                                        value={glslSettings}
                                                    />
                                                </Panel>
                                                <Panel>
                                                    <AceEditor
                                                        className="shadow-none"
                                                        height="100%"
                                                        width="100%"
                                                        mode="glsl"
                                                        name="collision-pass-reference"
                                                        setOptions={{ printMargin: 120, readOnly: true }}
                                                        value={glslCollisionPass}
                                                    />
                                                </Panel>
                                                <Panel>
                                                    <AceEditor
                                                        className="shadow-none"
                                                        height="100%"
                                                        width="100%"
                                                        mode="glsl"
                                                        name="lighting-pass-reference"
                                                        setOptions={{ printMargin: 120, readOnly: true }}
                                                        value={glslLightingPass}
                                                    />
                                                </Panel>
                                            </Tab.Panels>
                                        </Tab.Group>
                                    </Panel>
                                </Tab.Panels>
                            </Tab.Group>
                        </div>
                    </div>
                </div>
                <Gallery open={showGallery} onClose={handleCloseGallery} onSelect={handleSelectGalleryItem} />
            </main>
        </>
    )
}

export default Page
