import React from 'react'
import PropTypes from 'prop-types'
import StudioDiffusePreview from '/src/images/env-maps/studio-diffuse-material-preview.png'
import StudioMetallicPreview from '/src/images/env-maps/studio-metallic-material-preview.png'
import Outside1MetallicPreview from '/src/images/env-maps/outside1-metallic-material-preview.png'

export const MAPS = [
    {
        preview: StudioMetallicPreview,
        map: 'studio-metallic-bake.png',
    },
    {
        preview: StudioDiffusePreview,
        map: 'studio-diffuse-bake.png',
    },
    {
        preview: Outside1MetallicPreview,
        map: 'outside1-metallic-bake.png',
    },
]

export const MaterialPreviewThumbnail = ({ src, selected, ...props }) => {
    return (
        <div
            className={`rounded overflow-hidden cursor-pointer outline outline-2 outline-offset-2 ${
                selected ? 'outline-primary-800' : 'outline-transparent'
            }`}
            {...props}
        >
            <img src={src} />
        </div>
    )
}
MaterialPreviewThumbnail.propTypes = {
    selected: PropTypes.bool,
    src: PropTypes.string.isRequired,
}
export const EnvironmentMaps = (props) => {
    return (
        <div className="grid grid-cols-4 gap-4">
            {MAPS.map(({ preview, map }) => (
                <MaterialPreviewThumbnail
                    src={preview}
                    key={map}
                    selected={map === props.value}
                    onClick={() => {
                        props.onSelect && props.onSelect(map)
                    }}
                />
            ))}
        </div>
    )
}
EnvironmentMaps.propTypes = {
    onSelect: PropTypes.func,
    value: PropTypes.oneOf(MAPS.map(({ map }) => map)),
}
