import React from 'react'
import PropTypes from 'prop-types'

import { Dialog } from '@headlessui/react'

import glslMandelbulb from '/src/graphics/gl/sdfs/mandelbulb'
import glslMandelbulbLighting from '/src/graphics/gl/sdfs/mandelbulbLighting'
import gallery0 from '/src/images/distance-field-gallery/gallery0.png'
import gallery1 from '/src/images/distance-field-gallery/gallery1.png'
import glslMandelbox from '/src/graphics/gl/sdfs/mandelbox'
import glslMandelboxLighting from '/src/graphics/gl/sdfs/mandelboxLighting'

export const GALLERY = [
    {
        name: 'Mandelbulb',
        thumbnail: gallery0,
        collisionShader: glslMandelbulb,
        lightingShader: glslMandelbulbLighting,
    },
    {
        name: 'Mandelbox',
        thumbnail: gallery1,
        collisionShader: glslMandelbox,
        lightingShader: glslMandelboxLighting,
        envMapIndex: 1,
    },
]

export const Gallery = ({ onSelect, ...props }) => {
    return (
        <Dialog className="fixed z-10 inset-0 overflow-y-auto" {...props}>
            <div className="flex items-center justify-center min-h-screen">
                <Dialog.Overlay className="fixed inset-0 bg-neutral-900 opacity-50" />
                <div className="relative bg-zinc-900 text-white rounded-xl mx-auto w-4-xl">
                    <Dialog.Title className="text-lg font-medium my-4 mx-4">Gallery</Dialog.Title>
                    <div className="grid grid-cols-4 gap-4 m-4">
                        {GALLERY.map(({ name, thumbnail, ...item }) => (
                            <div
                                onClick={() => onSelect && onSelect(item)}
                                key={name}
                                className="cursor-pointer border border-zinc-500 rounded w-48 h-48"
                                style={{
                                    background: `url(${thumbnail}) center no-repeat`,
                                    backgroundSize: 'auto 100%',
                                }}
                            />
                        ))}
                    </div>
                </div>
            </div>
        </Dialog>
    )
}

Gallery.propTypes = {
    onSelect: PropTypes.func,
}
